@@ -0,0 +1,343 @@
+const PAYMENT_CONFIG = {
+  provider: 'paynoi',
+  apiKey:   null,
+  packages: []
+};
+
+let selectedPackage  = null;
+let _paynoiTransId   = null;
+let _pollInterval    = null;
+
+const PAYNOI_PROXY = 'https://wslevsdsbcqjndskwyhz.supabase.co/functions/v1/paynoi-proxy';
+
+/* ✅ helper เดียว — ใช้ทุกที่ ไม่ต้องซ้ำ header */
+async function _paynoiCall(body) {
+  const res = await fetch(PAYNOI_PROXY, {
+    method:  'POST',
+    headers: {
+      'Content-Type':  'application/json',
+      'Authorization': 'Bearer ' + CONFIG.SUPABASE_ANON
+    },
+    body: JSON.stringify(body)
+  });
+  return res.json();
+}
+
+/* ---- LOAD PACKAGES จาก Supabase ---- */
+async function loadPackages() {
+  const { data, error } = await _sb
+    .from('packages')
+    .select('*')
+    .eq('is_active', true)
+    .order('sort_order', { ascending: true });
+
+  if (error || !data?.length) return;
+
+  PAYMENT_CONFIG.packages = data.map(p => ({
+    id: p.id, coins: p.coins, bonus: p.bonus,
+    price: p.price, featured: p.is_featured, name: p.name
+  }));
+
+  const featuredList = data.filter(p => p.is_featured);
+  const normal       = data.filter(p => !p.is_featured);
+  const grid         = document.querySelector('.topup-grid');
+  if (!grid) return;
+
+  const normalHTML = normal.length ? `
+    <div class="topup-row-small">
+      ${normal.map(p => `
+        <div class="topup-opt" onclick="selPkg(this, ${p.coins}, '${p.id}')">
+          <div class="pkg-coins"><i class="fi fi-sr-coins"></i> ${p.coins + p.bonus}</div>
+          <div class="pkg-price">฿${p.price} บาท</div>
+          <div class="pkg-bonus"><i class="fi fi-sr-plus"></i> ${p.bonus > 0 ? p.bonus + ' โบนัส' : p.name}</div>
+        </div>`).join('')}
+    </div>` : '';
+
+  const featuredHTML = featuredList.map(p => `
+    <div class="topup-opt topup-featured topup-big" onclick="selPkg(this, ${p.coins}, '${p.id}')">
+      <div class="featured-badge"><i class="fi fi-sr-star"></i> โปรโมชั่นแนะนำ</div>
+      <div class="pkg-big-wrap">
+        <div class="pkg-coins pkg-coins-big"><i class="fi fi-sr-coins"></i> ${p.coins}</div>
+        <div class="pkg-big-right">
+          <div class="pkg-price-big">฿${p.price} บาท</div>
+          <div class="pkg-bonus"><i class="fi fi-sr-plus"></i> ${p.bonus} โบนัส</div>
+          <div class="pkg-per">คนเติมเยอะที่สุด</div>
+        </div>
+      </div>
+    </div>`).join('');
+
+  grid.innerHTML = normalHTML + featuredHTML;
+}
+
+/* =========================================
+   PAYNOI — สร้าง QR และรอจ่าย
+   ========================================= */
+
+async function initiatePayment() {
+  if (!selectedPackage) { toast('กรุณาเลือกแพ็กเกจก่อน', 'warning'); return; }
+  if (!currentUser)     { toast('กรุณาเข้าสู่ระบบก่อน', 'warning'); openLogin(); return; }
+    const { data: { session } } = await _sb.auth.getSession();
+  if (!session) { toast('Session หมดอายุ กรุณา login ใหม่', 'warning'); openLogin(); return; }
+
+  const cfg = CONFIG?.PAYNOI;
+  if (!cfg) { toast('ยังไม่ได้ตั้งค่าระบบชำระเงิน', 'error'); return; }
+
+  _stopPolling();
+
+  const btnPay = document.getElementById('btn-confirm-pay');
+  if (btnPay) { btnPay.disabled = true; btnPay.innerHTML = '<i class="fi fi-sr-spinner fi-spin"></i> กำลังสร้าง QR...'; }
+
+  try {
+    const ref1 = `uid_${currentUser.id}_${Date.now()}`;
+
+    const data = await _paynoiCall({
+      method:  'create',
+      amount:  selectedPackage.price,
+      ref1,
+      key_id:  cfg.KEY_ID,
+      account: cfg.ACCOUNT,
+      type:    cfg.ACCOUNT_TYPE
+    });
+
+    if (!data || data.status !== 1) {
+      throw new Error(data?.msg || 'สร้าง QR ไม่สำเร็จ');
+    }
+
+    _paynoiTransId = data.trans_id;
+
+    await _sb.from('credit_history').insert({
+      user_id: currentUser.id,
+      amount:  selectedPackage.coins + selectedPackage.bonus,
+      type:    'purchase_pending',
+      note:    `รอชำระ ${selectedPackage.price} บาท`,
+      tx_id:   data.trans_id
+    });
+
+    _showQRModal(data);
+    _startPolling(data.trans_id, selectedPackage.coins + selectedPackage.bonus);
+
+  } catch (e) {
+    console.error('initiatePayment error:', e);
+    toast(e.message || 'เกิดข้อผิดพลาด กรุณาลองใหม่', 'error');
+  } finally {
+    if (btnPay) { btnPay.disabled = false; btnPay.innerHTML = '<i class="fi fi-sr-credit-card"></i> ชำระเงิน'; }
+  }
+}
+
+/* ---- แสดง QR Modal ---- */
+function _showQRModal(data) {
+  let qrBox = document.getElementById('qr-pay-modal');
+  if (!qrBox) {
+    qrBox = document.createElement('div');
+    qrBox.id = 'qr-pay-modal';
+    qrBox.style.cssText = `
+      position:fixed;inset:0;background:rgba(0,0,0,.92);
+      z-index:700;display:flex;align-items:center;justify-content:center;
+      backdrop-filter:blur(8px);
+    `;
+    document.body.appendChild(qrBox);
+  }
+
+  const expireAt = new Date(data.expire_at);
+
+  qrBox.innerHTML = `
+    <div style="
+      background:linear-gradient(145deg,#181818,#101010);
+      border:1px solid #2a2a2a;border-radius:20px;
+      padding:32px 28px;max-width:340px;width:92%;
+      text-align:center;position:relative;
+    ">
+      <div style="position:absolute;top:0;left:0;right:0;height:2px;
+        background:linear-gradient(90deg,transparent,var(--red),transparent);
+        border-radius:20px 20px 0 0;"></div>
+
+      <div style="font-weight:900;font-size:1.2rem;letter-spacing:2px;margin-bottom:4px;">
+        สแกน <span style="color:var(--red);">QR</span> ชำระเงิน
+      </div>
+      <div style="color:var(--text2);font-size:.8rem;margin-bottom:16px;">
+        กรุณาโอนภายใน <span id="qr-countdown" style="color:var(--gold);font-weight:700;">15:00</span>
+      </div>
+
+      <img src="data:image/png;base64,${data.qr_image_base64}"
+           style="width:220px;height:220px;border-radius:12px;background:#fff;padding:8px;" />
+
+      <div style="margin-top:14px;font-size:.82rem;color:var(--text2);">
+        ยอดที่ต้องโอน
+      </div>
+      <div style="font-size:1.8rem;font-weight:900;color:var(--gold);margin:2px 0 4px;">
+        ฿${data.amount}
+      </div>
+      <div style="font-size:.72rem;color:var(--text3);margin-bottom:18px;">
+        ⚠️ โอนให้ตรงยอดนี้เท่านั้น (รวมทศนิยม)
+      </div>
+
+      <div id="qr-status-msg" style="
+        min-height:24px;font-size:.85rem;color:var(--text2);margin-bottom:14px;
+        display:flex;align-items:center;justify-content:center;gap:8px;
+      ">
+        <i class="fi fi-sr-spinner fi-spin"></i> รอการชำระเงิน...
+      </div>
+
+      <button onclick="_cancelQR()" style="
+        background:transparent;border:1px solid #333;color:var(--text2);
+        padding:9px 24px;border-radius:8px;cursor:pointer;
+        font-family:'Kanit',sans-serif;font-size:.85rem;width:100%;
+      ">ยกเลิก</button>
+    </div>
+  `;
+
+  qrBox.style.display = 'flex';
+  _startCountdown(expireAt);
+}
+
+/* ---- Countdown timer ---- */
+let _countdownTimer = null;
+function _startCountdown(expireAt) {
+  clearInterval(_countdownTimer);
+  _countdownTimer = setInterval(() => {
+    const el = document.getElementById('qr-countdown');
+    if (!el) { clearInterval(_countdownTimer); return; }
+    const diff = Math.max(0, Math.floor((expireAt - Date.now()) / 1000));
+    const m = String(Math.floor(diff / 60)).padStart(2, '0');
+    const s = String(diff % 60).padStart(2, '0');
+    el.textContent = `${m}:${s}`;
+    if (diff === 0) {
+      clearInterval(_countdownTimer);
+      el.textContent = 'หมดเวลา';
+      el.style.color = 'var(--red)';
+    }
+  }, 1000);
+}
+
+/* ---- Polling ตรวจสถานะ ---- */
+function _startPolling(transId, creditAmount) {
+  _pollInterval = setInterval(async () => {
+    try {
+      const data = await _paynoiCall({ method: 'check', trans_id: transId });
+      if (!data || data.status !== 1) return;
+
+      if (data.payment_status === 'completed') {
+        _stopPolling();
+        await _onPaymentSuccess(creditAmount, transId);
+      } else if (data.payment_status === 'failed' || data.payment_status === 'expired') {
+        _stopPolling();
+        _setQRStatus('ธุรกรรมหมดอายุหรือล้มเหลว', 'error');
+      }
+    } catch (e) {
+      console.warn('polling error:', e);
+    }
+  }, 5000);
+}
+
+function _stopPolling() {
+  clearInterval(_pollInterval);
+  clearInterval(_countdownTimer);
+  _pollInterval  = null;
+  _paynoiTransId = null;
+}
+
+function _setQRStatus(msg, type = 'info') {
+  const el = document.getElementById('qr-status-msg');
+  if (!el) return;
+  const colors = { success: '#4caf50', error: 'var(--red)', info: 'var(--text2)', warning: 'var(--gold)' };
+  const icons  = { success: 'fi-sr-check-circle', error: 'fi-sr-cross-circle', info: 'fi-sr-info', warning: 'fi-sr-bell-ring' };
+  el.style.color = colors[type] || colors.info;
+  el.innerHTML   = `<i class="fi ${icons[type] || icons.info}"></i> ${msg}`;
+}
+
+/* ---- เมื่อจ่ายสำเร็จ ---- */
+async function _onPaymentSuccess(creditAmount, transId) {
+  _setQRStatus('ชำระเงินสำเร็จ! กำลังเพิ่มเครดิต...', 'success');
+
+  credits = await API.addCredits(creditAmount);
+  updateCr();
+
+  await _sb.from('credit_history')
+    .update({ type: 'purchase', note: `ซื้อ ${creditAmount} เครดิต` })
+    .eq('tx_id', transId);
+
+  toast(`เติมเครดิตสำเร็จ! +${creditAmount} เครดิต`, 'success');
+
+  setTimeout(() => {
+    _closeQRModal();
+    closeTopup();
+  }, 1800);
+}
+
+/* ---- ปิด / ยกเลิก QR ---- */
+async function _cancelQR() {
+  const transId = _paynoiTransId;
+  _stopPolling();
+  if (transId) {
+    try { await _paynoiCall({ method: 'cancel', trans_id: transId }); }
+    catch(e) { /* ไม่สำคัญ */ }
+  }
+  _closeQRModal();
+}
+
+function _closeQRModal() {
+  const el = document.getElementById('qr-pay-modal');
+  if (el) el.style.display = 'none';
+}
+
+/* ---- ADD CREDITS ---- */
+async function applyTopup(amount) {
+  if (!currentUser) { toast('กรุณาเข้าสู่ระบบก่อน', 'warning'); return; }
+  credits = await API.addCredits(amount);
+  updateCr();
+  toast(`เติมเครดิตสำเร็จ! +${amount} เครดิต`, 'success');
+  closeTopup();
+}
+
+/* ---- FREE CREDITS (test mode only) ---- */
+const FREE_CREDIT_COOLDOWN_MS = 60 * 1000;
+
+async function freeCredit() {
+  if (!currentUser) { toast('กรุณาเข้าสู่ระบบก่อน', 'warning'); openLogin(); return; }
+  if (DB.settings?.testMode !== 1) { toast('โหมดทดสอบปิดอยู่', 'warning'); return; }
+
+  const lastFreeCr = parseInt(localStorage.getItem('last_free_cr') || '0');
+  const now = Date.now();
+  if (now - lastFreeCr < FREE_CREDIT_COOLDOWN_MS) {
+    const wait = Math.ceil((FREE_CREDIT_COOLDOWN_MS - (now - lastFreeCr)) / 1000);
+    toast(`รอ ${wait} วินาทีก่อนรับเครดิตฟรีอีกครั้ง`, 'warning');
+    return;
+  }
+
+  try {
+    localStorage.setItem('last_free_cr', now.toString());
+    await applyTopup(10);
+    _sb.from('credit_history').insert({
+      user_id: currentUser.id, amount: 10, type: 'free', note: 'รับเครดิตฟรี (ทดสอบ)'
+    }).then(({ error }) => { if (error) console.warn('history:', error.message); });
+  } catch (e) {
+    console.error('freeCredit error:', e);
+    localStorage.removeItem('last_free_cr');
+    toast('เกิดข้อผิดพลาด', 'error');
+  }
+}
+
+/* ---- PAYMENT HISTORY ---- */
+async function recordPayment(pkg, txId = null) {
+  if (!currentUser) return;
+  await _sb.from('credit_history').insert({
+    user_id: currentUser.id,
+    amount:  pkg.coins + pkg.bonus,
+    type:    'purchase',
+    note:    `ซื้อ ${pkg.coins + pkg.bonus} เครดิต (${pkg.price} บาท) ผ่าน paynoi`,
+    tx_id:   txId || ('tx_' + Date.now()),
+  });
+}
+
+async function getPaymentHistory() {
+  if (!currentUser) return [];
+  const { data, error } = await _sb
+    .from('credit_history')
+    .select('*')
+    .eq('user_id', currentUser.id)
+    .eq('type', 'purchase')
+    .order('created_at', { ascending: false })
+    .limit(50);
+  if (error) { console.error(error); return []; }
+  return data || [];
+}
